import{_ as a,c as i,o as n,a1 as r}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Funciones de Plataforma: Revisión de Planes y Código | Plannotator","description":"Aprende las funciones de plataforma de Plannotator, incluyendo revisión de planes y código. Domina habilidades esenciales como la revisión visual, agregar anotaciones y marcado de imágenes.","frontmatter":{"title":"Funciones de Plataforma: Revisión de Planes y Código | Plannotator","sidebarTitle":"Revisar Planes y Código con IA","subtitle":"Funciones de Plataforma: Revisión de Planes y Código","description":"Aprende las funciones de plataforma de Plannotator, incluyendo revisión de planes y código. Domina habilidades esenciales como la revisión visual, agregar anotaciones y marcado de imágenes.","order":2},"headers":[],"relativePath":"es/backnotprop/plannotator/platforms/index.md","filePath":"es/backnotprop/plannotator/platforms/index.md"}'),o={name:"es/backnotprop/plannotator/platforms/index.md"};function t(s,e,d,l,c,p){return n(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="funciones-de-plataforma" tabindex="-1">Funciones de Plataforma <a class="header-anchor" href="#funciones-de-plataforma" aria-label="Permalink to &quot;Funciones de Plataforma&quot;">​</a></h1><p>Esta sección introduce las dos funciones principales de Plannotator: <strong>Revisión de Planes</strong> y <strong>Revisión de Código</strong>. Aprenderás a revisar visualmente los planes generados por IA, agregar varios tipos de anotaciones, adjuntar marcadores de imagen y revisar los cambios de código git diff.</p><h2 id="prerrequisitos" tabindex="-1">Prerrequisitos <a class="header-anchor" href="#prerrequisitos" aria-label="Permalink to &quot;Prerrequisitos&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Confirma antes de comenzar</p><p>Antes de estudiar esta sección, asegúrate de haber completado los siguientes preparativos:</p><ul><li>✅ Completado el tutorial de <a href="./../start/getting-started/">Inicio Rápido</a></li><li>✅ Instalado el plugin de Plannotator (<a href="./../start/installation-claude-code/">Claude Code</a> u <a href="./../start/installation-opencode/">OpenCode</a>)</li></ul></div><h2 id="contenido-de-esta-seccion" tabindex="-1">Contenido de Esta Sección <a class="header-anchor" href="#contenido-de-esta-seccion" aria-label="Permalink to &quot;Contenido de Esta Sección&quot;">​</a></h2><h3 id="revision-de-planes" tabindex="-1">Revisión de Planes <a class="header-anchor" href="#revision-de-planes" aria-label="Permalink to &quot;Revisión de Planes&quot;">​</a></h3><p>Aprende a revisar los planes de ejecución generados por IA, agregar sugerencias de modificación y hacer que la IA ejecute según tus intenciones.</p><table tabindex="0"><thead><tr><th>Tutorial</th><th>Descripción</th></tr></thead><tbody><tr><td><a href="./plan-review-basics/">Fundamentos de Revisión de Planes</a></td><td>Aprende a usar Plannotator para revisar visualmente los planes generados por IA, incluyendo aprobar o rechazar planes</td></tr><tr><td><a href="./plan-review-annotations/">Agregar Anotaciones al Plan</a></td><td>Domina cómo agregar diferentes tipos de anotaciones al plan (eliminar, reemplazar, insertar, comentar)</td></tr><tr><td><a href="./plan-review-images/">Agregar Marcadores de Imagen</a></td><td>Aprende a adjuntar imágenes en la revisión de planes y usar herramientas de pincel, flecha y círculo para marcar</td></tr></tbody></table><h3 id="revision-de-codigo" tabindex="-1">Revisión de Código <a class="header-anchor" href="#revision-de-codigo" aria-label="Permalink to &quot;Revisión de Código&quot;">​</a></h3><p>Aprende a revisar cambios de código, agregar comentarios a nivel de línea y descubrir problemas antes de confirmar.</p><table tabindex="0"><thead><tr><th>Tutorial</th><th>Descripción</th></tr></thead><tbody><tr><td><a href="./code-review-annotations/">Agregar Comentarios de Código</a></td><td>Domina cómo agregar comentarios a nivel de línea en la revisión de código (comment/suggestion/concern)</td></tr><tr><td><a href="./code-review-diff-types/">Cambiar Vistas de Diff</a></td><td>Aprende a cambiar entre diferentes tipos de diff en la revisión de código (uncommitted/staged/last commit/branch)</td></tr></tbody></table><h2 id="rutas-de-aprendizaje" tabindex="-1">Rutas de Aprendizaje <a class="header-anchor" href="#rutas-de-aprendizaje" aria-label="Permalink to &quot;Rutas de Aprendizaje&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Orden de Aprendizaje Recomendado</p><p>Según tu caso de uso, elige la ruta de aprendizaje adecuada:</p><p><strong>Ruta A: Revisión de Planes Primero</strong> (recomendado para principiantes)</p><ol><li><a href="./plan-review-basics/">Fundamentos de Revisión de Planes</a> → Aprende primero el flujo básico de revisión de planes</li><li><a href="./plan-review-annotations/">Agregar Anotaciones al Plan</a> → Aprende a modificar planes con precisión</li><li><a href="./plan-review-images/">Agregar Marcadores de Imagen</a> → Usa imágenes para expresar intenciones más claramente</li><li>Luego aprende la serie de revisión de código</li></ol><p><strong>Ruta B: Revisión de Código Primero</strong> (adecuado para desarrolladores con experiencia en Code Review)</p><ol><li><a href="./code-review-basics/">Fundamentos de Revisión de Código</a> → Familiarízate con la interfaz de revisión de código</li><li><a href="./code-review-annotations/">Agregar Comentarios de Código</a> → Aprende comentarios a nivel de línea</li><li><a href="./code-review-diff-types/">Cambiar Vistas de Diff</a> → Domina diferentes tipos de diff</li><li>Luego aprende la serie de revisión de planes</li></ol></div><h2 id="siguientes-pasos" tabindex="-1">Siguientes Pasos <a class="header-anchor" href="#siguientes-pasos" aria-label="Permalink to &quot;Siguientes Pasos&quot;">​</a></h2><p>Después de completar esta sección, puedes continuar aprendiendo:</p><ul><li><a href="./../advanced/url-sharing/">Compartir URL</a> - Comparte planes y anotaciones a través de URL, logrando colaboración en equipo</li><li><a href="./../advanced/obsidian-integration/">Integración con Obsidian</a> - Guarda automáticamente los planes aprobados en Obsidian</li><li><a href="./../advanced/remote-mode/">Modo Remoto</a> - Usa Plannotator en entornos SSH, devcontainer, WSL</li></ul>',16)])])}const g=a(o,[["render",t]]);export{u as __pageData,g as default};
